+{
+    public:
+        typedef Vector<TemplateConfig<AMGX_host, t_vecPrec, t_matPrec, t_indPrec> > Vector_h;
+        typedef typename Vector_h::value_type ValueTypeVec;
+        typedef typename types::PODTypes<ValueTypeVec>::type ValueTypeNorm;
