-{
-    m_smem_count += m_gmem_count;
-#pragma unroll
-
-    for ( int offset = WARP_SIZE / 2 ; offset > 0 ; offset >>= 1 )
-    {
-        m_smem_count += utils::shfl_xor( m_smem_count, offset );
