+    }
+
+#pragma unroll 4
+
+    for ( int offset = lane_id ; offset < m_gmem_size ; offset += WARP_SIZE )
+    {
+        Key_type key = m_gmem_keys[offset];
+        int poll = utils::ballot( key != -1, utils::activemask() );
+
+        if ( poll == 0 )
